435	// Extensions
436	pub mod ext {
437	    use core::fmt;
438	
439	    use crate::{
440	        common::{imsg, ZExtZ64},
441	        core::{CongestionControl, EntityId, Priority, ZenohIdProto},
442	    };
443	
444	    /// ```text
445	    ///  7 6 5 4 3 2 1 0
446	    /// +-+-+-+-+-+-+-+-+
447	    /// |Z|0_1|    ID   |
448	    /// +-+-+-+---------+
449	    /// %0|r|F|E|D|prio %
450	    /// +---------------+
451	    ///
452	    /// - prio: Priority class
453	    /// - D:    Don't drop. Don't drop the message for congestion control.
454	    /// - E:    Express. Don't batch this message.
455	    /// - F:    Don't drop the first message for congestion control.
456	    /// - r:  Reserved
457	    /// ```
458	    #[repr(transparent)]
459	    #[derive(Clone, Copy, PartialEq, Eq)]
460	    pub struct QoSType<const ID: u8> {
461	        inner: u8,
462	    }
463	
464	    impl<const ID: u8> QoSType<{ ID }> {
465	        const P_MASK: u8 = 0b00000111;
466	        const D_FLAG: u8 = 0b00001000;
467	        const E_FLAG: u8 = 0b00010000;
468	        const F_FLAG: u8 = 0b00100000;
469	
470	        pub const DEFAULT: Self = Self::new(Priority::DEFAULT, CongestionControl::DEFAULT, false);
471	
472	        pub const DECLARE: Self =
473	            Self::new(Priority::Control, CongestionControl::DEFAULT_DECLARE, false);
474	        pub const INTEREST: Self = Self::new(
475	            Priority::Control,
476	            CongestionControl::DEFAULT_INTEREST,
477	            false,
478	        );
479	        pub const PUSH: Self = Self::new(Priority::DEFAULT, CongestionControl::DEFAULT_PUSH, false);
480	        pub const REQUEST: Self =
481	            Self::new(Priority::DEFAULT, CongestionControl::DEFAULT_REQUEST, false);
482	        pub const OAM: Self = Self::new(Priority::Control, CongestionControl::DEFAULT_OAM, false);
483	
484	        pub const fn new(
485	            priority: Priority,
486	            congestion_control: CongestionControl,
487	            is_express: bool,
488	        ) -> Self {
489	            let mut inner = priority as u8;
490	            match congestion_control {
491	                CongestionControl::Block => inner |= Self::D_FLAG,
492	                #[cfg(feature = "unstable")]
493	                CongestionControl::BlockFirst => inner |= Self::F_FLAG,
494	                _ => {}
495	            }
496	            if is_express {
497	                inner |= Self::E_FLAG;
498	            }
499	            Self { inner }
500	        }
501	
502	        pub fn set_priority(&mut self, priority: Priority) {
503	            self.inner = imsg::set_bitfield(self.inner, priority as u8, Self::P_MASK);
504	        }
505	
506	        pub const fn get_priority(&self) -> Priority {
507	            unsafe { core::mem::transmute(self.inner & Self::P_MASK) }
508	        }
509	
510	        pub fn set_congestion_control(&mut self, cctrl: CongestionControl) {
511	            match cctrl {
512	                CongestionControl::Block => {
513	                    self.inner = imsg::set_flag(self.inner, Self::D_FLAG);
514	                    self.inner = imsg::unset_flag(self.inner, Self::F_FLAG);
515	                }
516	                CongestionControl::Drop => {
517	                    self.inner = imsg::unset_flag(self.inner, Self::D_FLAG);
518	                    self.inner = imsg::unset_flag(self.inner, Self::F_FLAG);
519	                }
520	                #[cfg(feature = "unstable")]
521	                CongestionControl::BlockFirst => {
522	                    self.inner = imsg::unset_flag(self.inner, Self::D_FLAG);
523	                    self.inner = imsg::set_flag(self.inner, Self::F_FLAG);
524	                }
525	            }
526	        }
527	
528	        pub const fn get_congestion_control(&self) -> CongestionControl {
529	            match (
530	                imsg::has_flag(self.inner, Self::D_FLAG),
531	                imsg::has_flag(self.inner, Self::F_FLAG),
532	            ) {
533	                (false, false) => CongestionControl::Drop,
534	                #[cfg(feature = "unstable")]
535	                (false, true) => CongestionControl::BlockFirst,
536	                #[cfg(not(feature = "unstable"))]
537	                (false, true) => CongestionControl::Drop,
538	                (true, _) => CongestionControl::Block,
539	            }
540	        }
541	
542	        pub fn set_is_express(&mut self, is_express: bool) {
543	            match is_express {
544	                true => self.inner = imsg::set_flag(self.inner, Self::E_FLAG),
545	                false => self.inner = imsg::unset_flag(self.inner, Self::E_FLAG),
546	            }
547	        }
548	
549	        pub const fn is_express(&self) -> bool {
550	            imsg::has_flag(self.inner, Self::E_FLAG)
551	        }
552	
553	        #[cfg(feature = "test")]
554	        #[doc(hidden)]
555	        pub fn rand() -> Self {
556	            use rand::Rng;
557	            let mut rng = rand::thread_rng();
558	
559	            let inner: u8 = rng.gen();
560	            Self { inner }
561	        }
562	    }
563	
564	    impl<const ID: u8> Default for QoSType<{ ID }> {
565	        fn default() -> Self {
566	            Self::new(Priority::DEFAULT, CongestionControl::DEFAULT, false)
567	        }
568	    }
569	
570	    impl<const ID: u8> From<ZExtZ64<{ ID }>> for QoSType<{ ID }> {
571	        fn from(ext: ZExtZ64<{ ID }>) -> Self {
572	            Self {
573	                inner: ext.value as u8,
574	            }
575	        }
576	    }
577	
578	    impl<const ID: u8> From<QoSType<{ ID }>> for ZExtZ64<{ ID }> {
579	        fn from(ext: QoSType<{ ID }>) -> Self {
580	            ZExtZ64::new(ext.inner as u64)
581	        }
582	    }
583	
584	    impl<const ID: u8> fmt::Debug for QoSType<{ ID }> {
585	        fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
586	            f.debug_struct("QoS")
587	                .field("priority", &self.get_priority())
588	                .field("congestion", &self.get_congestion_control())
589	                .field("express", &self.is_express())
590	                .finish()
591	        }
592	    }
