633	
634	    impl<const ID: u8> NodeIdType<{ ID }> {
635	        // node_id == 0 means the message has been generated by the node itself
636	        pub const DEFAULT: Self = Self { node_id: 0 };
637	
638	        #[cfg(feature = "test")]
639	        #[doc(hidden)]
640	        pub fn rand() -> Self {
641	            use rand::Rng;
642	            let mut rng = rand::thread_rng();
643	            let node_id = rng.gen();
644	            Self { node_id }
645	        }
646	    }
647	
648	    impl<const ID: u8> Default for NodeIdType<{ ID }> {
649	        fn default() -> Self {
650	            Self::DEFAULT
651	        }
652	    }
653	
654	    impl<const ID: u8> From<ZExtZ64<{ ID }>> for NodeIdType<{ ID }> {
655	        fn from(ext: ZExtZ64<{ ID }>) -> Self {
656	            Self {
657	                node_id: ext.value as u16,
658	            }
659	        }
660	    }
661	
662	    impl<const ID: u8> From<NodeIdType<{ ID }>> for ZExtZ64<{ ID }> {
663	        fn from(ext: NodeIdType<{ ID }>) -> Self {
664	            ZExtZ64::new(ext.node_id as u64)
665	        }
666	    }
667	
668	    /// ```text
669	    ///  7 6 5 4 3 2 1 0
670	    /// +-+-+-+-+-+-+-+-+
671	    /// |zid_len|X|X|X|X|
672	    /// +-------+-+-+---+
673	    /// ~      zid      ~
674	    /// +---------------+
675	    /// %      eid      %
676	    /// +---------------+
677	    /// ```
678	    #[derive(Debug, Clone, PartialEq, Eq)]
679	    pub struct EntityGlobalIdType<const ID: u8> {
680	        pub zid: ZenohIdProto,
681	        pub eid: EntityId,
682	    }
683	
684	    impl<const ID: u8> EntityGlobalIdType<{ ID }> {
685	        #[cfg(feature = "test")]
686	        #[doc(hidden)]
687	        pub fn rand() -> Self {
688	            use rand::Rng;
689	            let mut rng = rand::thread_rng();
690	
691	            let zid = ZenohIdProto::rand();
692	            let eid: EntityId = rng.gen();
693	            Self { zid, eid }
694	        }
695	    }
