14	use alloc::string::String;
15	use core::{convert::TryFrom, fmt, num::NonZeroU8, ops::BitOr, str::FromStr};
16	
17	use const_format::formatcp;
18	use serde::ser::SerializeSeq;
19	use zenoh_result::{bail, ZError};
20	
21	/// The type of the node in the Zenoh network.
22	///
23	/// The zenoh application can work in three different modes: router, peer, and client.
24	///
25	/// In the peer mode the application searches for other nodes and establishes direct connections
26	/// with them. This can work using multicast discovery and by getting gossip information
27	/// from the initial entry points. The peer mode is the default mode.
28	///
29	/// In the client mode the application remains connected to a single connection point, which
30	/// serves as a gateway to the rest of the network. This mode is useful for constrained
31	/// devices that cannot afford to maintain multiple connections.
32	///
33	/// The router mode is used to run a zenoh router, which is a node that
34	/// maintains a predefined zenoh network topology. Unlike peers, routers do not
35	/// discover other nodes by themselves, but rely on static configuration.
36	///
37	/// A more detailed explanation of each mode is at [Zenoh Documentation](https://zenoh.io/docs/getting-started/deployment/)
38	#[repr(u8)]
39	#[derive(Debug, Default, Clone, Copy, PartialEq, Eq, Hash, PartialOrd, Ord)]
40	pub enum WhatAmI {
41	    Router = 0b001,
42	    #[default]
43	    Peer = 0b010,
44	    Client = 0b100,
45	}
46	
47	impl WhatAmI {
48	    const STR_R: &'static str = "router";
49	    const STR_P: &'static str = "peer";
50	    const STR_C: &'static str = "client";
51	
52	    const U8_R: u8 = Self::Router as u8;
53	    const U8_P: u8 = Self::Peer as u8;
54	    const U8_C: u8 = Self::Client as u8;
55	
56	    pub const fn to_str(self) -> &'static str {
57	        match self {
58	            Self::Router => Self::STR_R,
59	            Self::Peer => Self::STR_P,
60	            Self::Client => Self::STR_C,
61	        }
62	    }
63	
64	    #[cfg(feature = "test")]
65	    #[doc(hidden)]
66	    pub fn rand() -> Self {
67	        use rand::prelude::SliceRandom;
68	        let mut rng = rand::thread_rng();
69	
70	        *[Self::Router, Self::Peer, Self::Client]
71	            .choose(&mut rng)
72	            .unwrap()
73	    }
74	
75	    pub const fn is_client(self) -> bool {
76	        matches!(self, WhatAmI::Client)
77	    }
78	
79	    pub const fn is_peer(self) -> bool {
80	        matches!(self, WhatAmI::Peer)
81	    }
82	
83	    pub const fn is_router(self) -> bool {
84	        matches!(self, WhatAmI::Router)
85	    }
86	}
87	
88	impl TryFrom<u8> for WhatAmI {
89	    type Error = ();
90	
91	    fn try_from(v: u8) -> Result<Self, Self::Error> {
92	        match v {
93	            Self::U8_R => Ok(Self::Router),
94	            Self::U8_P => Ok(Self::Peer),
95	            Self::U8_C => Ok(Self::Client),
96	            _ => Err(()),
97	        }
98	    }
99	}
100	
101	impl FromStr for WhatAmI {
102	    type Err = ZError;
103	
104	    fn from_str(s: &str) -> Result<Self, Self::Err> {
105	        match s {
106	            Self::STR_R => Ok(Self::Router),
107	            Self::STR_P => Ok(Self::Peer),
108	            Self::STR_C => Ok(Self::Client),
109	            _ => bail!(
110	                "{s} is not a valid WhatAmI value. Valid values are: {}, {}, {}.",
111	                Self::STR_R,
112	                Self::STR_P,
113	                Self::STR_C
114	            ),
115	        }
116	    }
117	}
118	
119	impl fmt::Display for WhatAmI {
120	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
121	        f.write_str(self.to_str())
122	    }
123	}
124	
125	impl From<WhatAmI> for u8 {
126	    fn from(w: WhatAmI) -> Self {
127	        w as u8
128	    }
129	}
130	
131	/// A helper type that allows matching combinations of `WhatAmI` values in scouting.
132	///
133	/// The [`scout`](crate::scouting::scout) function accepts a `WhatAmIMatcher` to filter the nodes
134	/// of the specified types. The `WhatAmIMatcher` can be constructed from [`WhatAmI`] values
135	/// with the `|` operator
